4	export function makePolicy(items: Item[]): Policy {
5	  for (const item of items) {
6	    if (!isKnownType(item.type)) {
7	      throw new Error(`Unknown item type: ${item.type}`);
8	    }
9	  }
10	  let insuranceSum = 0;
11	  for (const item of items) {
12	    insuranceSum += insuranceValueOf(item.type);
13	  }
14	  const cap = insuranceSum * 2;
15	  return {
16	    items,
17	    insuranceSum,
18	    cap,
19	    remainingCap: cap,
20	  };
21	}
