1	import { Item, Customer } from './types.js';
2	import {
3	  getItemSpec,
4	  isComponentType,
5	  isKnownType,
6	  COMPONENT_BLOCK_PREMIUM,
7	  COMPONENT_BLOCK_SIZE,
8	} from './catalogue.js';
9	
10	const CURSE_SURCHARGE = 0.5;
11	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT = 0.2;
14	const LOYALTY_YEARS = 2;
15	const FIRST_INSURANCE_SURCHARGE = 0.1;
16	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
17	const PROCESSING_FEE = 5;
18	
19	function basePremiumForItem(item: Item): number {
20	  if (isComponentType(item.type)) {
21	    return getItemSpec(item.type).basePremium;
22	  }
23	  return getItemSpec(item.type).basePremium;
24	}
25	
26	function componentsBasePremium(items: Item[]): number {
27	  const groups: Record<string, number> = {};
28	  for (const item of items) {
29	    if (isComponentType(item.type)) {
30	      groups[item.type] = (groups[item.type] || 0) + 1;
31	    }
32	  }
33	  let total = 0;
34	  for (const type of Object.keys(groups)) {
35	    const count = groups[type];
36	    const spec = getItemSpec(type);
37	    if (count === COMPONENT_BLOCK_SIZE) {
38	      total += COMPONENT_BLOCK_PREMIUM;
39	    } else {
40	      const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
41	      // Per spec: "block requires exactly 3" - 4 runes -> 100 G (no block).
42	      // But 3+3 = 120 G (two separate blocks). So blocks apply only when exact match.
43	      // Reading again: "3 runes → 60 G (block applies)"; "4 runes → 100 G (no block — block requires exactly 3)";
44	      // "3 runes + 3 moonstones → 120 G base premium (two separate blocks)".
45	      // So per-type: if count == 3 then block, else full price each. What about 6 runes? Unspecified.
46	      // Safest: only exactly 3 of one type triggers the block.
47	      void blocks;
48	      total += count * spec.basePremium;
49	    }
50	  }
51	  return total;
52	}
53	
54	function mainItemsBasePremium(items: Item[]): number {
55	  let total = 0;
56	  for (const item of items) {
57	    if (!isComponentType(item.type)) {
58	      total += getItemSpec(item.type).basePremium;
59	    }
60	  }
61	  return total;
62	}
63	
64	function itemBasePremiumWithItemModifiers(item: Item): number {
65	  const base = basePremiumForItem(item);
66	  let surcharge = 0;
67	  if (item.cursed) {
68	    surcharge += base * CURSE_SURCHARGE;
69	  }
70	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
71	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE;
72	  }
73	  return base + surcharge;
74	}
75	
76	function policyBaseWithComponentBlocks(items: Item[]): number {
77	  return mainItemsBasePremium(items) + componentsBasePremium(items);
78	}
79	
80	function itemSpecificSurcharges(items: Item[]): number {
81	  let total = 0;
82	  for (const item of items) {
83	    const base = basePremiumForItem(item);
84	    if (item.cursed) {
85	      total += base * CURSE_SURCHARGE;
86	    }
87	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
88	      total += base * HIGH_ENCHANTMENT_SURCHARGE;
89	    }
90	  }
91	  return total;
92	}
93	
94	function validateItems(items: Item[]): void {
95	  for (const item of items) {
96	    if (!isKnownType(item.type)) {
97	      throw new Error(`Unknown item type: ${item.type}`);
98	    }
99	  }
100	}
101	
102	export interface PremiumContext {
103	  customer: Customer;
104	  quoteIndex: number; // 0-based index among quotes in scenario
105	}
106	
107	export function computePremium(items: Item[], ctx: PremiumContext): number {
108	  validateItems(items);
109	
110	  const policyBase = policyBaseWithComponentBlocks(items);
111	  const itemSurcharges = itemSpecificSurcharges(items);
112	
113	  let total = policyBase + itemSurcharges;
114	
115	  // Policy-wide modifiers apply to the policy base premium (sum of item base premiums)
116	  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS) {
117	    total -= policyBase * LOYALTY_DISCOUNT;
118	  }
119	  // First insurance: per spec, each item in a quote is a first insurance.
120	  // The integration example shows: 100 base + 50 curse + 30 high + 10 first
121	  // -20 loyalty - 15 followup = 155 + 5 fee = 160.
122	  // Loyalty -20 = 20% of 100 (policy base). First insurance +10 = 10% of 100.
123	  // Followup -15 = 15% of 100.
124	  // So all policy-wide modifiers apply to policyBase.
125	  total += policyBase * FIRST_INSURANCE_SURCHARGE;
126	
127	  if (ctx.quoteIndex > 0) {
128	    total -= policyBase * FOLLOWUP_CONTRACT_DISCOUNT;
129	  }
130	
131	  total += PROCESSING_FEE;
132	
133	  // Round up in MHPCO's favor
134	  return Math.ceil(total);
135	}
