1	export const MAIN_ITEM_TYPES = ['sword', 'amulet', 'staff', 'potion'] as const;
2	export const COMPONENT_TYPES = ['rune', 'moonstone'] as const;
3	export const KNOWN_TYPES = [...MAIN_ITEM_TYPES, ...COMPONENT_TYPES] as const;
4	
5	export interface ItemSpec {
6	  insuranceValue: number;
7	  basePremium: number;
8	}
9	
10	const MAIN_ITEMS: Record<string, ItemSpec> = {
11	  sword: { insuranceValue: 1000, basePremium: 100 },
12	  amulet: { insuranceValue: 600, basePremium: 60 },
13	  staff: { insuranceValue: 800, basePremium: 80 },
14	  potion: { insuranceValue: 400, basePremium: 40 },
15	};
16	
17	const COMPONENT_ITEM: ItemSpec = { insuranceValue: 250, basePremium: 25 };
18	export const COMPONENT_BLOCK_PREMIUM = 60;
19	export const COMPONENT_BLOCK_SIZE = 3;
20	
21	export function isKnownType(type: string): boolean {
22	  return (KNOWN_TYPES as readonly string[]).includes(type);
23	}
24	
25	export function isComponentType(type: string): boolean {
26	  return (COMPONENT_TYPES as readonly string[]).includes(type);
27	}
28	
29	export function getItemSpec(type: string): ItemSpec {
30	  if (MAIN_ITEMS[type]) return MAIN_ITEMS[type];
31	  if (isComponentType(type)) return COMPONENT_ITEM;
32	  throw new Error(`Unknown item type: ${type}`);
33	}
34	
35	export function insuranceValueOf(type: string): number {
36	  return getItemSpec(type).insuranceValue;
37	}
