1	import { Policy, Incident, DamageEntry, Item, ClaimResult } from './types.js';
2	import { isKnownType } from './catalogue.js';
3	
4	const DEDUCTIBLE = 100;
5	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
6	const HIGH_ENCHANTMENT_PAYOUT_FACTOR = 0.5;
7	const DRAGON_MATERIAL = 'dragon';
8	
9	function matchDamagesToItems(items: Item[], damages: DamageEntry[]): Item[] {
10	  // Allocate each damage to one item of the same type.
11	  // If there are more damages of a type than items, throw.
12	  const itemsByType: Record<string, Item[]> = {};
13	  for (const item of items) {
14	    if (!itemsByType[item.type]) itemsByType[item.type] = [];
15	    itemsByType[item.type].push(item);
16	  }
17	  // Track consumption per type
18	  const consumed: Record<string, number> = {};
19	  const matched: Item[] = [];
20	  for (const damage of damages) {
21	    if (!isKnownType(damage.itemType)) {
22	      throw new Error(`Unknown damaged item type: ${damage.itemType}`);
23	    }
24	    const available = itemsByType[damage.itemType];
25	    const used = consumed[damage.itemType] || 0;
26	    if (!available || used >= available.length) {
27	      throw new Error(
28	        `Damage references ${damage.itemType} not covered by the policy`
29	      );
30	    }
31	    matched.push(available[used]);
32	    consumed[damage.itemType] = used + 1;
33	  }
34	  return matched;
35	}
36	
37	function payoutForDamage(item: Item, amount: number): number {
38	  if (amount < 0) {
39	    throw new Error(`Damage amount must be non-negative, got ${amount}`);
40	  }
41	  let reimbursable = amount;
42	  const isDragon = item.material === DRAGON_MATERIAL;
43	  const isHighEnchant =
44	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
45	
46	  if (isHighEnchant && !isDragon) {
47	    reimbursable = amount * HIGH_ENCHANTMENT_PAYOUT_FACTOR;
48	  }
49	  // Dragon material: full reimbursement (overrides high enchantment per spec?)
50	  // Actually the spec says:
51	  //   dragon, ench 9, damage 1000 -> payout 400 (both clauses; 50% wins, then deductible)
52	  // So when BOTH apply, the 50% rule wins.
53	  // Re-check: "dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G
54	  //  (high-enchantment clause applies, then deductible)" → 500 - 100 = 400.
55	  // So 50% always wins over dragon when both apply.
56	  if (isHighEnchant) {
57	    reimbursable = amount * HIGH_ENCHANTMENT_PAYOUT_FACTOR;
58	  } else if (isDragon) {
59	    reimbursable = amount;
60	  }
61	
62	  const afterDeductible = reimbursable - DEDUCTIBLE;
63	  return Math.max(0, afterDeductible);
64	}
65	
66	export function processClaim(policy: Policy, incident: Incident): ClaimResult {
67	  const matchedItems = matchDamagesToItems(policy.items, incident.damages);
68	
69	  // Validate amounts first (negative check)
70	  for (const damage of incident.damages) {
71	    if (damage.amount < 0) {
72	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
73	    }
74	  }
75	
76	  let totalPayout = 0;
77	  for (let i = 0; i < incident.damages.length; i++) {
78	    totalPayout += payoutForDamage(matchedItems[i], incident.damages[i].amount);
79	  }
80	
81	  // Round payouts down (in MHPCO's favor)
82	  let payout = Math.floor(totalPayout);
83	
84	  // Apply remaining cap
85	  if (payout > policy.remainingCap) {
86	    payout = policy.remainingCap;
87	  }
88	  policy.remainingCap -= payout;
89	
90	  return {
91	    payout,
92	    remainingCap: policy.remainingCap,
93	  };
94	}
