1	import { Scenario, ScenarioResult, StepResult, Policy } from './types.js';
2	import { computePremium } from './premium.js';
3	import { makePolicy } from './policy.js';
4	import { processClaim } from './claim.js';
5	
6	export function runScenario(scenario: Scenario): ScenarioResult {
7	  const results: StepResult[] = [];
8	  const policies: Record<number, Policy> = {};
9	  let quoteCount = 0;
10	
11	  for (let i = 0; i < scenario.steps.length; i++) {
12	    const step = scenario.steps[i];
13	    if (step.op === 'quote') {
14	      const premium = computePremium(step.items, {
15	        customer: scenario.customer,
16	        quoteIndex: quoteCount,
17	      });
18	      const policy = makePolicy(step.items);
19	      policies[i] = policy;
20	      quoteCount += 1;
21	      results.push({ premium });
22	    } else if (step.op === 'claim') {
23	      const policy = policies[step.policy];
24	      if (!policy) {
25	        throw new Error(
26	          `Claim step ${i} references non-existent policy ${step.policy}`
27	        );
28	      }
29	      const claimResult = processClaim(policy, step.incident);
30	      results.push(claimResult);
31	    } else {
32	      throw new Error(`Unknown step op: ${(step as { op: string }).op}`);
33	    }
34	  }
35	
36	  return { results };
37	}
